package main

import (
	"html/template"
	"net/http"
)

type Comment struct {
	Username string
	Content  string
}

var comments = []Comment{
	{"alice", "Hello world!"},
	{"bob", "This is a <b>bold</b> comment"},
	{"charlie", "Check out this <a href='http://example.com'>link</a>"},
}

func main() {
	http.HandleFunc("/", handler)
	http.ListenAndServe(":8080", nil)
}

func handler(w http.ResponseWriter, r *http.Request) {
	tmpl := template.New("comments").Funcs(template.FuncMap{
		"safeHTML": func(s string) template.HTML {
			return template.HTML(s)
		},
	})
	tmpl, err := tmpl.Parse(`
<!DOCTYPE html>
<html>
<head>
    <title>Comments</title>
</head>
<body>
    <h1>Comments</h1>
    {{range .}}
    <div>
        <strong>{{.Username}}</strong>
        <p>{{safeHTML .Content}}</p>
    </div>
    <hr>
    {{end}}
</body>
</html>
`)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}

	err = tmpl.Execute(w, comments)
	if err != nil {
		http.Error(w, err.Error(), http.StatusInternalServerError)
		return
	}
}